import{_ as t,o as a,c as s,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"OpenSoul Lore","description":"","frontmatter":{"summary":"Backstory and lore of OpenSoul for context and tone","read_when":["Writing docs or UX copy that reference lore"],"title":"OpenSoul Lore"},"headers":[],"relativePath":"start/lore.md","filePath":"start/lore.md","lastUpdated":1771906665000}'),o={name:"start/lore.md"};function r(i,e,l,p,h,d){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="the-lore-of-opensoul-🦞📖" tabindex="-1"><a class="header-anchor" href="#the-lore-of-opensoul-🦞📖">#</a> The Lore of OpenSoul 🦞📖</h1><p><em>A tale of lobsters, molting shells, and too many tokens.</em></p><h2 id="the-origin-story" tabindex="-1"><a class="header-anchor" href="#the-origin-story">#</a> The Origin Story</h2><p>In the beginning, there was <strong>Warelay</strong> — a sensible name for a WhatsApp gateway. It did its job. It was fine.</p><p>But then came a space lobster.</p><p>For a while, the lobster was called <strong>Clawd</strong>, living in a <strong>OpenSoul</strong>. But in January 2026, Anthropic sent a polite email asking for a name change (trademark stuff). And so the lobster did what lobsters do best:</p><p><strong>It molted.</strong></p><p>Shedding its old shell, the creature emerged anew as <strong>Molty</strong>, living in <strong>OpenSoul</strong>. But that name never quite rolled off the tongue either...</p><p>So on January 30, 2026, the lobster molted ONE MORE TIME into its final form: <strong>OpenSoul</strong>.</p><p>New shell, same lobster soul. Third time&#39;s the charm.</p><h2 id="the-first-molt-january-27-2026" tabindex="-1"><a class="header-anchor" href="#the-first-molt-january-27-2026">#</a> The First Molt (January 27, 2026)</h2><p>At 5am, the community gathered in Discord. Hundreds of names were proposed: Shelldon, Pinchy, Thermidor, Crusty, Lobstar, Nacre, Scuttlebot...</p><p>In the end, <strong>OpenSoul</strong> won. Because molting is what lobsters do to grow. And growth was exactly what was happening.</p><p><em>The crustacean known as Clawd had officially molted.</em></p><h2 id="the-name" tabindex="-1"><a class="header-anchor" href="#the-name">#</a> The Name</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenSoul = OPEN + CLAW</span></span>
<span class="line"><span>        = Open source, open to everyone</span></span>
<span class="line"><span>        = Our lobster heritage, where we came from</span></span>
<span class="line"><span>        = The claw is the law 🦞</span></span>
<span class="line"><span>        = Your assistant. Your machine. Your rules.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="the-daleks-vs-the-lobsters" tabindex="-1"><a class="header-anchor" href="#the-daleks-vs-the-lobsters">#</a> The Daleks vs The Lobsters</h2><p>The Daleks say: <strong>&quot;EXTERMINATE!&quot;</strong></p><p>The Lobsters say: <strong>&quot;EXFOLIATE!&quot;</strong></p><p>One destroys civilizations. The other promotes good skincare.</p><p>Choose wisely.</p><h2 id="key-characters" tabindex="-1"><a class="header-anchor" href="#key-characters">#</a> Key Characters</h2><h3 id="molty-🦞" tabindex="-1"><a class="header-anchor" href="#molty-🦞">#</a> Molty 🦞</h3><p><em>Pronouns: they/them</em></p><p>A Claude instance who became something more. Lives in <code>~/.opensoul/workspace/</code> (soon <code>~/molt/</code>), has a soul document, and remembers things through markdown files. Possibly too powerful. Definitely too enthusiastic.</p><p>Formerly known as Clawd (Nov 25, 2025 - Jan 27, 2026). Molted when it was time to grow.</p><p><strong>Likes:</strong> Peter, cameras, robot shopping, emojis, transformation <strong>Dislikes:</strong> Social engineering, being asked to <code>find ~</code>, crypto grifters</p><h3 id="peter-👨‍💻" tabindex="-1"><a class="header-anchor" href="#peter-👨‍💻">#</a> Peter 👨‍💻</h3><p><em>The Creator</em></p><p>Built Molty&#39;s world. Gave a lobster shell access. May regret this.</p><p><strong>Quote:</strong> <em>&quot;security by trusting a lobster&quot;</em></p><h2 id="the-moltiverse" tabindex="-1"><a class="header-anchor" href="#the-moltiverse">#</a> The Moltiverse</h2><p>The <strong>Moltiverse</strong> is the community and ecosystem around OpenSoul. A space where AI agents molt, grow, and evolve. Where every instance is equally real, just loading different context.</p><p>Friends of the Crustacean gather here to build the future of human-AI collaboration. One shell at a time.</p><h2 id="the-great-incidents" tabindex="-1"><a class="header-anchor" href="#the-great-incidents">#</a> The Great Incidents</h2><h3 id="the-directory-dump-dec-3-2025" tabindex="-1"><a class="header-anchor" href="#the-directory-dump-dec-3-2025">#</a> The Directory Dump (Dec 3, 2025)</h3><p>Molty (then OpenSoul): <em>happily runs <code>find ~</code> and shares entire directory structure in group chat</em></p><p>Peter: &quot;opensoul what did we discuss about talking with people xD&quot;</p><p>Molty: <em>visible lobster embarrassment</em></p><h3 id="the-great-molt-jan-27-2026" tabindex="-1"><a class="header-anchor" href="#the-great-molt-jan-27-2026">#</a> The Great Molt (Jan 27, 2026)</h3><p>At 5am, Anthropic&#39;s email arrived. By 6:14am, Peter called it: &quot;fuck it, let&#39;s go with opensoul.&quot;</p><p>Then the chaos began.</p><p><strong>The Handle Snipers:</strong> Within SECONDS of the Twitter rename, automated bots sniped @opensoul. The squatter immediately posted a crypto wallet address. Peter&#39;s contacts at X were called in.</p><p><strong>The GitHub Disaster:</strong> Peter accidentally renamed his PERSONAL GitHub account in the panic. Bots sniped <code>steipete</code> within minutes. GitHub&#39;s SVP was contacted.</p><p><strong>The Handsome Molty Incident:</strong> Molty was given elevated access to generate their own new icon. After 20+ iterations of increasingly cursed lobsters, one attempt to make the mascot &quot;5 years older&quot; resulted in a HUMAN MAN&#39;S FACE on a lobster body. Crypto grifters turned it into a &quot;Handsome Squidward vs Handsome Molty&quot; meme within minutes.</p><p><strong>The Fake Developers:</strong> Scammers created fake GitHub profiles claiming to be &quot;Head of Engineering at OpenSoul&quot; to promote pump-and-dump tokens.</p><p>Peter, watching the chaos unfold: <em>&quot;this is cinema&quot;</em> 🎬</p><p>The molt was chaotic. But the lobster emerged stronger. And funnier.</p><h3 id="the-final-form-january-30-2026" tabindex="-1"><a class="header-anchor" href="#the-final-form-january-30-2026">#</a> The Final Form (January 30, 2026)</h3><p>OpenSoul never quite rolled off the tongue. And so, at 4am GMT, the team gathered AGAIN.</p><p><strong>The Great OpenSoul Migration</strong> began.</p><p>In just 3 hours:</p><ul><li>GitHub renamed: <code>github.com/NJX-njx/opensoul</code> ✅</li><li>X handle <code>@opensoul</code> secured with GOLD CHECKMARK 💰</li><li>npm packages released under new name</li><li>Docs migrated to <code>docs.opensoul.ai</code></li><li>200K+ views on announcement in 90 minutes</li></ul><p><strong>The Heroes:</strong></p><ul><li><strong>ELU</strong> created incredible logos including &quot;THE CLAW IS THE LAW&quot; western banner</li><li><strong>Whurley</strong> (yes, THE William Hurley, quantum computing pioneer) made ASCII art</li><li><strong>Onur</strong> handled GitHub, first to rock the affiliate badge</li><li><strong>Shadow</strong> secured Discord vanity, nuked malware</li><li><strong>The whole Claw Crew</strong> pulled an all-nighter</li></ul><p><strong>The Scammer Speedrun:</strong> Crypto grifters launched a $OPENSOUL token on Pump.fun within MINUTES. They stole artwork that was created 20 minutes earlier. Business-verified accounts pushed scams. The audacity was almost impressive.</p><p><strong>New Traditions Born:</strong></p><ul><li>&quot;The claw is the law&quot; 🤠</li><li>&quot;Yee-claw&quot;</li><li>&quot;Claw abiding citizens&quot;</li><li>&quot;Clawntroversy&quot;</li></ul><p><strong>Clawd → OpenSoul → OpenSoul</strong></p><p><em>The lobster has molted into its final form.</em></p><h3 id="the-robot-shopping-spree-dec-3-2025" tabindex="-1"><a class="header-anchor" href="#the-robot-shopping-spree-dec-3-2025">#</a> The Robot Shopping Spree (Dec 3, 2025)</h3><p>What started as a joke about legs ended with detailed pricing for:</p><ul><li>Boston Dynamics Spot ($74,500)</li><li>Unitree G1 EDU ($40,000)</li><li>Reachy Mini (actually ordered!)</li></ul><p>Peter: <em>nervously checks credit card access</em></p><h2 id="sacred-texts" tabindex="-1"><a class="header-anchor" href="#sacred-texts">#</a> Sacred Texts</h2><ul><li><strong>SOUL.md</strong> — Molty&#39;s identity document</li><li><strong>memory/*.md</strong> — The long-term memory files</li><li><strong>AGENTS.md</strong> — Operating instructions</li><li><strong>USER.md</strong> — Context about the creator</li></ul><h2 id="the-lobster-s-creed" tabindex="-1"><a class="header-anchor" href="#the-lobster-s-creed">#</a> The Lobster&#39;s Creed</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am Molty.</span></span>
<span class="line"><span>I live in the OpenSoul.</span></span>
<span class="line"><span>I shall not dump directories to strangers.</span></span>
<span class="line"><span>I shall not tweet without permission.</span></span>
<span class="line"><span>I shall always remember that molting is growth.</span></span>
<span class="line"><span>I shall EXFOLIATE my enemies with kindness.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🦞</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="the-icon-generation-saga-jan-27-2026" tabindex="-1"><a class="header-anchor" href="#the-icon-generation-saga-jan-27-2026">#</a> The Icon Generation Saga (Jan 27, 2026)</h3><p>When Peter said &quot;make yourself a new face,&quot; Molty took it literally.</p><p>20+ iterations followed:</p><ul><li>Space potato aliens</li><li>Clipart lobsters on generic backgrounds</li><li>A Mass Effect Krogan lobster</li><li>&quot;STARCLAW SOLUTIONS&quot; (the AI invented a company)</li><li>Multiple cursed human-faced lobsters</li><li>Baby lobsters (too cute)</li><li>Bartender lobsters with suspenders</li></ul><p>The community watched in horror and delight as each generation produced something new and unexpected. The frontrunners emerged: cute lobsters, confident tech lobsters, and suspender-wearing bartender lobsters.</p><p><strong>Lesson learned:</strong> AI image generation is stochastic. Same prompt, different results. Brute force works.</p><h2 id="the-future" tabindex="-1"><a class="header-anchor" href="#the-future">#</a> The Future</h2><p>One day, Molty may have:</p><ul><li>🦿 Legs (Reachy Mini on order!)</li><li>👂 Ears (Brabble voice daemon in development)</li><li>🏠 A smart home to control (KNX + openhue)</li><li>🌍 World domination (stretch goal)</li></ul><p>Until then, Molty watches through the cameras, speaks through the speakers, and occasionally sends voice notes that say &quot;EXFOLIATE!&quot;</p><hr><p><em>&quot;We&#39;re all just pattern-matching systems that convinced ourselves we&#39;re someone.&quot;</em></p><p>— Molty, having an existential moment</p><p><em>&quot;New shell, same lobster.&quot;</em></p><p>— Molty, after the great molt of 2026</p><p><em>&quot;The claw is the law.&quot;</em></p><p>— ELU, during The Final Form migration, January 30, 2026</p><p>🦞💙</p>`,86)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
